module top_module(clk,reset,key,IRQ,Key_RD);input clk;
    input reset;

    input [7:0] key;


    output reg IRQ;
    output [31:0] Key_RD;


    reg [7:0] ctrl;

    assign Key_RD={24'b0,ctrl};

    always @(posedge clk)
        begin
            if(reset)
                begin
                    ctrl<=0;
                    IRQ<=0;
                end 
            else if(ctrl!=~key)
                begin
                    ctrl<=~key;
                    IRQ<=1;
                end
            else
                begin
                    ctrl<=ctrl;
                    IRQ<=0;
                end
        end

endmodule
